mapper.select:
SELECT ROUND(
                       (
                           SELECT COUNT(1)
                           FROM xm_answer_report
                           WHERE score < #{score}
                       ) / (
                           SELECT COUNT(1)
                           FROM xm_answer_report
                           WHERE course_id = #{courseId}
                       ) * 100, 2)

SELECT id, submit_time, answer_time, score
FROM xm_answer_report
WHERE is_delete = 0
  AND type = 1
  AND project_id = #{projectId}
  AND person_id = #{personId}

SELECT SUM(answered_questions) AS answered_questions, SUM(right_questions) AS right_questions FROM xm_answer_report WHERE id IN ( SELECT MAX(a.id) AS id FROM xm_answer_report a WHERE a.type = 3 AND a.person_id = #{personId}
AND a.course_id IN ( SELECT relate_ids FROM xm_project_relate WHERE project_id = #{projectId} AND type = 2 AND is_delete = 0 )
AND a.course_id = #{courseId}
GROUP BY course_id )
